    }

    // 1. Calculate Prefix Maximums (PMax[i] = max(nums[0]...nums[i]))
    const pMax = new Array(n);
    pMax[0] = nums[0];
    for (let i = 1; i < n; i++) {
        pMax[i] = Math.max(pMax[i - 1], nums[i]);
    }

    // 2. Calculate Suffix Minimums (SMin[i] = min(nums[i]...nums[n-1]))
    const sMin = new Array(n);
    sMin[n - 1] = nums[n - 1];
    for (let i = n - 2; i >= 0; i--) {
        sMin[i] = Math.min(sMin[i + 1], nums[i]);
    }

    // 3. Find the Minimum Stable Index
    for (let i = 0; i < n; i++) {
        // Instability = PMax[i] - SMin[i]
        // Since nums[i] and k are within safe integer limits for JS numbers, standard subtraction is fine.
        const instability = pMax[i] - sMin[i];

        if (instability <= k) {
            return i;
        }
    }

    // If no stable index is found
    return -1;
}
